import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import BookCard from "../components/BookCard";
import "./Home.css";

export default function Home() {
  const [books, setBooks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    fetch("http://127.0.0.1:5000/api/popular")
      .then((r) => r.json())
      .then((data) => {
        setBooks(data);
        setLoading(false);
      })
      .catch(() => {
        setError("Could not load books. Is Flask running?");
        setLoading(false);
      });
  }, []);

  return (
    <div className="home">
      
      {/* ══════════════════════════════════════
         CINEMATIC HERO (HBO STYLE)
      ══════════════════════════════════════ */}
      <section className="cinematic-hero">
        <div className="cinematic-hero__bg"></div>

        <div className="cinematic-hero__content container">
          
          {/* Left: Timeline */}
          <div className="cinematic-timeline">
            <span className="ct-dot"></span>
            <span className="ct-dot"></span>
            <span className="ct-dot ct-dot--active"></span>
            <span className="ct-dot"></span>
            <span className="ct-dot"></span>
            <span className="ct-line"></span>
          </div>

          {/* Left: Info */}
          <div className="cinematic-hero__left">
            <div className="cinematic-stars">
              <span className="c-star">★</span>
              <span className="c-star">★</span>
              <span className="c-star">★</span>
              <span className="c-star">★</span>
              <span className="c-star c-star--half">★</span>
              <span className="c-rating-text">9.8 / 10 Match</span>
            </div>

            <h1 className="cinematic-title">
              Discover Books <br /> You'll Love
            </h1>
            
            <p className="cinematic-desc">
              Our collaborative filtering engine analyses millions of reader
              preferences to surface the perfect next book — just for you.
            </p>

            <Link to="/recommend" className="cinematic-btn">
              <span className="cinematic-btn__icon">▶</span>
              Get Recommendations
            </Link>

            <div className="cinematic-badge">Trending Reads</div>
          </div>

          {/* Right: Featured Cards */}
          <div className="cinematic-hero__right">
            <div className="cinematic-cards">
              {loading ? (
                <>
                  <div className="cinematic-card skeleton" style={{ width: 240, height: 340, flexShrink: 0 }} />
                  <div className="cinematic-card skeleton" style={{ width: 240, height: 340, flexShrink: 0 }} />
                </>
              ) : (
                books.slice(0, 3).map((b, i) => (
                  <div key={i} className="cinematic-card" style={{ backgroundImage: `url(${b.image})` }}>
                    <div className="cinematic-card__overlay">
                      <div className="cinematic-bookmark">
                        <svg width="16" height="20" viewBox="0 0 16 20" fill="none" stroke="currentColor" strokeWidth="2">
                          <path d="M1 1V19L8 15L15 19V1Z" />
                        </svg>
                      </div>
                      <div className="cinematic-card__info">
                        <span className="cc-rank">Rank {i + 1}</span>
                        <h4 className="cc-title">{b.title}</h4>
                        <span className="cc-rating">★ {b.rating}</span>
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>

            {/* Controls */}
            <div className="cinematic-controls">
              <div className="cinematic-arrows">
                <button className="c-arrow">‹</button>
                <button className="c-arrow">›</button>
              </div>
              <div className="cinematic-pagination">
                <strong>01</strong> <span>—</span> 03
              </div>
            </div>
          </div>

        </div>
      </section>

      {/* ══════════════════════════════════════
         TOP 50 BOOKS 
      ══════════════════════════════════════ */}
      <section className="top50-section" id="top50">
        <div className="container">

          <div className="top50-header">
            <div>
              <h2 className="top50-title">Top 50 Books</h2>
              <p className="top50-sub">
                Ranked by community ratings & popularity
              </p>
            </div>

            <Link to="/recommend" className="top50-cta">
              Find Similar Books →
            </Link>
          </div>

          {error && <div className="top50-error">⚠️ {error}</div>}

          {loading ? (
            <div className="books-grid">
              {Array(12).fill(0).map((_, i) => (
                <div key={i} className="book-skeleton">
                  <div
                    className="skeleton"
                    style={{
                      height: 280,
                      borderRadius: 12,
                      marginBottom: 12,
                    }}
                  />
                  <div
                    className="skeleton"
                    style={{ height: 14, borderRadius: 6, marginBottom: 8 }}
                  />
                  <div
                    className="skeleton"
                    style={{ height: 12, width: "65%", borderRadius: 6 }}
                  />
                </div>
              ))}
            </div>
          ) : (
            <div className="books-grid">
              {books.map((b, i) => (
                <BookCard
                  key={i}
                  title={b.title}
                  author={b.author}
                  image={b.image}
                  rating={b.rating}
                  votes={b.votes}
                  rank={i + 1}
                  delay={Math.min(i * 35, 700)}
                />
              ))}
            </div>
          )}

        </div>
      </section>

      {/* ══════════════════════════════════════
         HOW IT WORKS 
      ══════════════════════════════════════ */}
      <section className="how-section" id="how-it-works">
        <div className="container">

          <h2 className="how-title">How It Works</h2>
          <p className="how-sub">Three steps to your next favourite book</p>

          <div className="how-steps">
            {[
              {
                icon: "🔍",
                step: "01",
                title: "Search a Book",
                desc: "Enter any book title you already enjoy into our search bar.",
              },
              {
                icon: "🤖",
                step: "02",
                title: "AI Analyses",
                desc: "Our model finds readers with similar tastes and surfaces their favourites.",
              },
              {
                icon: "📚",
                step: "03",
                title: "Discover Reads",
                desc: "Get 4 personalised recommendations with match scores.",
              },
            ].map((s) => (
              <div key={s.step} className="how-card">
                <div className="how-card__icon">{s.icon}</div>
                <div className="how-card__step">{s.step}</div>
                <h3>{s.title}</h3>
                <p>{s.desc}</p>
              </div>
            ))}
          </div>

        </div>
      </section>

    </div>
  );
}
